+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The wrapped schema.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  let resolved: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
+  const schema: RecursiveSchema<TWrapped> = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    wrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return resolved['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TWrapped>;
+  resolved = _resolveRecur(wrapped, schema);
+  return schema;
+}
+
+/**
+ * Resolves recur placeholders in a schema.
+ *
+ * @param value The value to resolve.
+ * @param schema The recursive schema.
+ *
+ * @returns The resolved value.
+ *
+ * @internal
+ */
+export function _resolveRecur<TValue>(
+  value: TValue,
+  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): TValue {
+  const values = new WeakMap<object, unknown>();
+
+  const resolve = (current: unknown): unknown => {
+    if (current === Recur) {
+      return schema;
+    }
+    if (!current || typeof current !== 'object') {
+      return current;
+    }
+    const cached = values.get(current);
+    if (cached) {
+      return cached;
+    }
+    const copy: object = Array.isArray(current)
+      ? []
+      : Object.create(Object.getPrototypeOf(current));
+    values.set(current, copy);
+    for (const [key, descriptor] of Object.entries(
+      Object.getOwnPropertyDescriptors(current)
+    )) {
+      if ('value' in descriptor) {
+        descriptor.value = resolve(descriptor.value);
+      }
+      Object.defineProperty(copy, key, descriptor);
+    }
+    return copy;
+  };
+
+  return resolve(value) as TValue;
+}
